$enabled_elements = array_filter(
			$enabled_elements,
			function ( $value, $key ) {
				return ( strpos( $key, 'premium-' ) === 0 || strpos( $key, 'mini-' ) === 0 || strpos( $key, 'woo-' ) === 0 ) && filter_var( $value, FILTER_VALIDATE_BOOLEAN );
			},
			ARRAY_FILTER_USE_BOTH
		)

